import { Component, ChangeDetectionStrategy, signal, inject } from '@angular/core';
import { MatCardModule } from '@angular/material/card';
import { MatFormFieldModule } from '@angular/material/form-field';
import {
  FormBuilder,
  FormControl,
  FormGroup,
  FormsModule,
  ReactiveFormsModule,
  Validators,
} from '@angular/forms';
import { MatButtonModule } from '@angular/material/button';
import { MatGridListModule } from '@angular/material/grid-list';
import { MatInputModule } from '@angular/material/input';
import { MatSelectModule } from '@angular/material/select';
import { Router, RouterModule } from '@angular/router';
import { MatExpansionModule } from '@angular/material/expansion';
import { MatIconModule } from '@angular/material/icon';
import { BankFormModel } from './bank-form.model';
import { CommonModule } from '@angular/common';
import { SharedService } from '../shared-service-bankForm-review-continue';
import { PortAgentFormService } from '../../../components/port-agent-form/port-agent-form.service';
import { LoaderService } from '../../../shared/loader/loader.service';
import { MaCountry } from '../../master/country/country.model';
import { map, Observable, startWith } from 'rxjs';
import { MatAutocompleteModule } from '@angular/material/autocomplete';

@Component({
  selector: 'app-bank-form',
  standalone: true,
  imports: [
    MatCardModule,
    MatButtonModule,
    MatGridListModule,
    MatFormFieldModule,
    MatInputModule,
    FormsModule,
    ReactiveFormsModule,
    MatSelectModule,
    RouterModule,
    MatExpansionModule,
    MatIconModule,
    CommonModule,
    MatAutocompleteModule
  ],
  templateUrl: './bank-form.component.html',
  styleUrl: './bank-form.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class BankFormComponent {
  loader = inject(LoaderService);
  isLoading = this.loader.loading;
  bankDetails: FormGroup;
  countryList: MaCountry[] = []
  data: BankFormModel = new BankFormModel();
  response = JSON.parse(sessionStorage.getItem("pa-success-response") || '{}')
  billing_address: FormControl = new FormControl(this.response?.billing_address, Validators.required);

  constructor(private routes: Router, private fb: FormBuilder, private sharedService: SharedService, private portAgentFormService: PortAgentFormService) {
    this.data = this.response?.bank_details
    this.bankDetails = this.fb.group({
      bank_details_id: [this.data?.bank_details_id || null],
      beneficiary_acc_holder_name: [this.data?.beneficiary_acc_holder_name || '', Validators.required],
      current_account_number: [this.data?.current_account_number?.toString() || '', [
        Validators.required,
        Validators.pattern(/^\d+$/)
      ]],
      bank_name: [this.data?.bank_name || ''],
      correspondent_account_number: [this.data?.correspondent_account_number || ''],
      swift_code: [this.data?.swift_code || ''],
      branch_address: [this.data?.branch_address || ''],
      country_name: [this.data?.country_name || null],
      currency: [this.data?.currency || ''],
      inn_code: [this.data?.inn_code || ''],
      bik_code: [this.data?.bik_code || ''],
      ifsc_code: [this.data?.ifsc_code || ''],
      bic_code: [this.data?.bic_code || ''],
      iban_number: [this.data?.iban_number || ''],

    });

  }

  onSubmit() {

  }
  disableSaveButton = (): boolean => {
    return !this.bankDetails.valid;
  }

  filteredCountries!: Observable<any[]>;

  ngOnInit() {
    this.getAllMasterData();
    this.filteredCountries = this.bankDetails.get('country_name')!.valueChanges.pipe(
      startWith(''),
      map(value => this._filter(value || ''))
    );

  }

  // method to get the master country data
  getAllMasterData(): void {
    this.loader.show();
    const params = {
      fields: ['country']
    };
    this.portAgentFormService.getMasterData(params).subscribe({
      next: (response: any) => {
        this.countryList = response.country;
        this.loader.hide();
      },
      error: (err: any) => {
        this.loader.hide();
      }
    });
  }

  // method to filter the countries
  private _filter(value: string): any[] {
    const filterValue = value.toLowerCase();
    return this.countryList.filter(country =>
      country?.name && country.name.toLowerCase().includes(filterValue)
    );
  }

  step = signal(0);

  setStep(index: number) {
    this.step.set(index);
  }

  nextStep() {

    if (this.billing_address.valid) {
      this.step.update(i => i + 1);
    }
    else {
      this.billing_address.markAllAsTouched()
    }

  }

  prevStep() {
    this.step.update(i => i - 1);
  }

  returnPda = (): void => {
    this.routes.navigate(['/pdfa/returnPda']);
  };

  save = (): void => {
    const addressAndBankDetails = {
      address: this.billing_address.value,
      bankDetails: this.bankDetails.value
    }
    // this.sharedService.sendBankDetails(addressAndBankDetails)
    sessionStorage.setItem("addressAndBankDetails", JSON.stringify(addressAndBankDetails));
    this.routes.navigate(['/pdfa/reviewContinue']);
  };
}
